  ) as s(category_slug, subcategory_slug, text, difficulty, explanation, law_name, law_article, source_url, law_version_date, is_prime, option_a, option_b, option_c, option_d, correct_option)
  loop
    insert into public.law_articles(law_id, article_number, version_date, is_active)
    values (v_law_id, r.law_article, nullif(r.law_version_date,'')::date, true)
    on conflict (law_id, article_number) do update set version_date=excluded.version_date, is_active=true
    returning id into v_article_id;

    select q.id into v_question_id from public.questions q where q.law_id=v_law_id and q.text=r.text limit 1;
    if v_question_id is null then
      insert into public.questions(category_id, subcategory_id, text, difficulty, explanation, law_name, law_article, source_url, law_version_date, is_prime, law_id, primary_law_article_id, verified_at, needs_review, is_published)
      values (v_category_id, v_subcategory_id, r.text, r.difficulty::public.difficulty, r.explanation, r.law_name, r.law_article, nullif(r.source_url,''), nullif(r.law_version_date,'')::date, false, v_law_id, v_article_id, now(), false, true)
      returning id into v_question_id;
    else
      update public.questions set category_id=v_category_id, subcategory_id=v_subcategory_id, difficulty=r.difficulty::public.difficulty, explanation=r.explanation, law_name=r.law_name, law_article=r.law_article, source_url=nullif(r.source_url,''), law_version_date=nullif(r.law_version_date,'')::date, is_prime=false, law_id=v_law_id, primary_law_article_id=v_article_id, verified_at=coalesce(verified_at, now()), needs_review=false, is_published=true, updated_at=now()
      where id=v_question_id;
    end if;

    delete from public.question_options where question_id=v_question_id;
    insert into public.question_options(question_id, option_text, is_correct, sort_order)
    values (v_question_id,r.option_a,r.correct_option='A',1),(v_question_id,r.option_b,r.correct_option='B',2),(v_question_id,r.option_c,r.correct_option='C',3),(v_question_id,r.option_d,r.correct_option='D',4);

    insert into public.question_law_articles(question_id, law_article_id, is_primary)
    values (v_question_id, v_article_id, true)
    on conflict (question_id, law_article_id) do update set is_primary=true;
  end loop;
end $$;
